```javascript
/**
 * 创建一个 debounce（防抖）函数
 *
 * 防抖的核心思想：在连续触发的事件中，只有在最后一次触发后
 * 等待 `delay` 毫秒没有新触发，才真正执行回调函数。
 *
 * @param {Function} fn       - 需要防抖包装的回调函数
 * @param {number}   delay    - 延迟时间，单位毫秒
 * @param {Object}   options  - 可选配置
 * @param {boolean}  [options.leading=false] - 是否在首次触发时立即执行（领先调用）
 * @param {boolean}  [options.trailing=true] - 是否在停止触发后延迟执行（尾随调用）
 * @returns {Function} 经过防抖处理的新函数，附带 `.cancel()` 和 `.flush()` 方法
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;

  // 边界检查：leading 和 trailing 不能同时为 false
  if (leading === false && trailing === false) {
    throw new Error('至少需要开启 leading 或 trailing 中的一个');
  }

  let timer = null;       // setTimeout 的句柄
  let lastArgs = null;    // 最后一次调用的参数
  let lastThis = null;    // 最后一次调用的 this 上下文
  let lastCallTime = 0;   // 最后一次调用 debounced 函数的时间戳
  let result = undefined; // 最近一次执行 fn 的返回值

  /**
   * 判断是否应该立即执行（leading 模式）
   */
  function shouldInvokeLeading(time) {
    return leading && (time - lastCallTime >= delay);
  }

  /**
   * 实际执行回调
   */
  function invokeFunc() {
    const args = lastArgs;
    const ctx = lastThis;

    lastArgs = lastThis = null;
    result = fn.apply(ctx, args);
    return result;
  }

  /**
   * 启动或重启定时器（trailing 模式）
   */
  function startTimer(remainingWait) {
    // 如果已有定时器则清除
    if (timer) {
      clearTimeout(timer);
    }

    timer = setTimeout(() => {
      timer = null;
      // trailing 模式下执行
      if (trailing && lastArgs) {
        invokeFunc();
      }
    }, remainingWait);
  }

  /**
   * 到达延迟边界时的处理函数
   */
  function edgeTimerExpired() {
    const time = Date.now();
    // 检查是否在等待期间又有新的调用
    if (lastArgs) {
      // 重新计算剩余等待时间
      const timeSinceLastCall = time - lastCallTime;
      const remainingWait = delay - timeSinceLastCall;

      if (remainingWait <= 0) {
        // 等待时间已到，执行 trailing
        if (trailing) {
          invokeFunc();
        }
        // 清理后重新进入等待状态
        timer = null;
        lastArgs = lastThis = null;
      } else {
        // 等待时间未到，继续等待
        startTimer(remainingWait);
      }
    } else {
      // 没有等待的调用，清理定时器
      timer = null;
    }
  }

  /**
   * debounced 函数本体
   */
  function debounced(...args) {
    const time = Date.now();
    const isFirstCall = lastCallTime === 0;

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    // 首次调用且 leading 开启 → 立即执行
    if (isFirstCall && leading) {
      invokeFunc();
    }

    // 如果已经有定时器在跑，说明还在等待期内
    // 主流程交给 edgeTimerExpired 在超时回调中处理
    if (timer === null) {
      // 没有定时器，启动一个
      startTimer(delay);
    }
  }

  /**
   * 取消防抖，取消即将到来的执行
   */
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = lastThis = null;
    lastCallTime = 0;
  };

  /**
   * 立即执行当前等待中的调用（如果有）
   */
  debounced.flush = function () {
    if (timer && lastArgs) {
      // 清除当前定时器
      clearTimeout(timer);
      timer = null;
      // 立即执行
      invokeFunc();
    }
  };

  return debounced;
}
```

---

## 配合使用示例

```javascript
// 1. 基础用法：输入框搜索防抖（尾随执行）
const searchInput = document.querySelector('#search');
const doSearch = debounce((keyword) => {
  console.log('发起搜索:', keyword);
}, 500);

searchInput.addEventListener('input', (e) => {
  doSearch(e.target.value);
});

// 2. leading 模式：提交按钮防连点（首次立即执行，防止重复提交）
const submitBtn = document.querySelector('#submit');
const handleSubmit = debounce(
  () => { console.log('提交表单'); },
  2000,
  { leading: true, trailing: false }
);
submitBtn.addEventListener('click', handleSubmit);

// 3. 取消与强制刷新
const resizeHandler = debounce(() => {
  console.log('resize 结束');
}, 300);
window.addEventListener('resize', resizeHandler);
// 手动取消
resizeHandler.cancel();
// 强制执行当前排队任务
resizeHandler.flush();
```

---

## 要点总结

| 概念 | 说明 |
|------|------|
| **trailing**（默认） | 停止触发后 `delay` 毫秒执行一次 |
| **leading** | 首次触发时**立即**执行，后续在等待期内不再执行 |
| **cancel()** | 取消防抖，清空计时器和待执行参数 |
| **flush()** | 立即执行当前等待中的调用 |
| 应用场景 | 搜索框联想、窗口 resize、按钮防连点、滚动加载 |

